mapper.update:
update `orders`
set status = 4,
    submitted_at = #{submittedAt},
    progress_percent = #{progressPercent},
    updated_at = now()
where id = #{id}
  and developer_id = #{developerId}
  and current_stage_no = #{currentStageNo}
  and status = 3

update `orders`
set status = 3,
    progress_percent = #{progressPercent},
    updated_at = now()
where id = #{id}
  and client_id = #{clientId}
  and current_stage_no = #{currentStageNo}
  and status = 4

update `orders`
set status = 3,
    current_stage_no = #{nextStageNo},
    progress_percent = #{progressPercent},
    updated_at = now()
where id = #{id}
  and client_id = #{clientId}
  and current_stage_no = #{currentStageNo}
  and status = 4
